INSERT INTO quiz_question (id, word_bank_id, contextual_cloze, chinese_translation, correct_answer, distractor1, distractor2, distractor3, explanation_root_affix, explanation_mnemonic, created_at, updated_at) VALUES
('b9775501-bd72-5e35-88d2-1c93b7e82313', '99b43fee-0272-4385-af84-355cb3d5eaef', 'The scientist felt a great sense of ___ after discovering the new vaccine.', '這位科學家在發現新疫苗後感到巨大的成就感。', 'accomplishment', 'confusion', 'pressure', 'movement', '前綴 ac- (向/去) + 詞根 compl (填滿/完成) → 徹底完成某事 → 成就。', 'ac (去) + compl (完成) → 去把事情做完並達到目標 → 成就。', '2026-07-06 16:51:33', '2026-07-06 16:51:33'),
('90ce3add-c2d1-59bb-9f93-815cd07d4eb3', '910341d4-7734-4b02-afcb-d666e12a1167', 'Transitioning into ___ often involves taking on more financial and personal responsibilities.', '邁向成年時期通常涉及承擔更多的經濟與個人責任。', 'adulthood', 'childhood', 'friendship', 'leadership', 'adult (成年人) + -hood (狀態、時期) → 成年時期', '記住 adult 是大人，-hood 表示一個時期，結合起來就是成年時期。', '2026-07-06 18:01:46', '2026-07-06 18:01:46'),
('34ebcebf-8647-5a99-81f2-7761f47db23b', 'ea571e44-c014-4ca4-9f2e-f2da487afbfb', 'He couldn''t hide his ___ when he saw his broken toy.', '當他看到弄壞的玩具時，他無法掩飾他的憤怒。', 'anger', 'joy', 'fear', 'hunger', 'anger 為名詞，表示一種強烈的情緒，即「憤怒」。', '想像一個很生氣的人臉紅脖子粗，那就是 anger。', '2026-07-06 14:08:59', '2026-07-06 14:08:59'),
('0bca12fc-cf99-5734-8ad9-1a9e3a3fabe3', '3d7411ab-c1fe-426c-abf9-adfb768b70b5', 'You can contact me ___ if you encounter any problems with the project.', '如果你在專案中遇到任何問題，你隨時可以聯絡我。', 'anytime', 'anywhere', 'anyway', 'somehow', 'any (任何) + time (時間) → 在任何時間。', 'any (任何) 結合 time (時間) → 任何時間 → 隨時。', '2026-07-06 22:31:33', '2026-07-06 22:31:33'),
('021bfeea-5b70-534b-a40b-4c469c524a8b', '402e0dba-8226-4c80-b3ac-7620b067e927', 'The coach ordered all the players to ___ on the field before the game started.', '教練命令所有球員在比賽開始前在球場上集合。', 'assemble', 'depart', 'ignore', 'expand', 'ad- (向) + semble (像) → 聚在一起變得像是一樣 → 集合、組裝。', '想像一群人向 (as) 同樣 (semble) 的方向靠攏 → 集合。', '2026-07-07 00:57:01', '2026-07-07 00:57:01'),
('127e5bfd-d676-5923-ab70-3934a7858c77', 'a4fe84aa-3bee-420f-a6f7-945354162a2e', 'I put my books and pencil case into my ___.', '我把書本和筆袋放進了我的___。', 'backpack', 'pocket', 'wallet', 'umbrella', 'back (背部) + pack (裝、打包) → 背包。', '想像把東西 pack (打包) 在你的 back (背部) 上，就是 backpack。', '2026-07-07 01:45:53', '2026-07-07 01:45:53'),
('81bd43f4-95e9-532c-8a37-cdfc9c80b093', '68fd55bf-90a5-4163-b8e3-037cad785255', 'The soldiers returned to their military ___ after the mission.', '任務結束後，士兵們回到了他們的軍事基地。', 'base', 'park', 'zoo', 'farm', 'base 作為名詞時，代表基地或基礎 (base → 基地)。', '想像一個軍事基地 (base)，是士兵們休息與出發的地方。', '2026-07-07 02:27:07', '2026-07-07 02:27:07'),
('d5a9bd66-1fb3-54a5-b0d9-85ea51bda7bf', '57c79f27-020c-481c-96ca-ee5562a72c52', 'The children promised to ___ well during the museum tour.', '孩子們承諾在博物館參觀期間會表現得很乖。', 'behave', 'believe', 'borrow', 'become', 'be- 表示處於某種狀態，have 表示擁有，合起來指「表現出」某種行為或舉止。', '想一下 be (處於) + have (擁有) → 擁有某種行為的樣子 → 表現。', '2026-07-07 03:14:46', '2026-07-07 03:14:46'),
('4e9bdddc-0fba-5215-a848-365e6c3600e3', '9e62b720-49af-4048-88bc-1fb7ed46986c', 'The teacher is writing the homework on the ___.', '老師正在黑板上寫作業。', 'blackboard', 'notebook', 'window', 'ceiling', '由 black (黑色) 與 board (板子) 兩個單字組合而成。', '看到 black (黑色) + board (板子) → 黑色的板子 → 黑板。', '2026-07-07 03:51:19', '2026-07-07 03:51:19'),
('57b33937-122d-5e0c-97bf-ba6cf9842fdb', '2c8847af-b6ec-4e33-a281-e5b0dd2159bd', 'I don''t like this book because the story is very ___.', '我不喜歡這本書，因為故事非常乏味。', 'boring', 'funny', 'hungry', 'careful', 'bore (使厭煩) + ing (形容詞字尾，用來修飾事物)', '當你覺得某件事物讓你覺得沒意思、很悶時 → boring。', '2026-07-07 05:10:03', '2026-07-07 05:10:03'),
('ec530ce8-9b52-5f2f-8c05-07e0b8766257', '6dc788fc-92f4-4e98-b0a8-5ad4c774bd86', 'In our PE class today, we played ___ with our classmates.', '在今天的體育課上，我們和同學們一起玩躲避球。', 'dodge ball', 'basketball', 'chess', 'soccer', 'dodge (躲避) + ball (球)。', '想像你在球場上要 dodge (躲避) 飛來的 ball (球)，就是 dodge ball！', '2026-07-07 04:58:04', '2026-07-07 04:58:04'),
('14ba0526-d8d4-5085-923a-2b0d952b3177', 'fccc0972-d0d7-42fd-b711-f3c828d4cd85', 'It is ___ to make a sandwich.', '做三明治是很簡單的。', 'easy', 'fast', 'loud', 'tall', '描述難度低。', 'Easy 唸起來很輕快，就像事情很容易。', '2026-07-07 03:10:30', '2026-07-07 03:10:30'),
('ab5a2a37-c23e-5902-9d4d-b03fa128a803', '8a59b946-647f-49e8-af12-269c1fb6860a', 'I am ___ Taiwan.', '我來自台灣。', 'from', 'to', 'at', 'in', '介系詞，用來表示來源、起點或出處。', '看到「來自...」或「出身於...」，就聯想 from → 來自。', '2026-07-06 10:33:34', '2026-07-06 10:33:34'),
('23fd9a56-a453-5419-8109-ff1cfc06f75f', 'c06ad5b8-1e6c-4f00-8470-7f8a5418e1cc', 'He is ___ the bus now.', '他現在在公車上。', 'on', 'in', 'at', 'by', '介係詞，用於搭乘大型交通工具（如公車、火車）。', '搭乘大型交通工具時，人是在該工具的平面上，所以用 on。', '2026-07-05 11:51:15', '2026-07-05 11:51:15'),
('2b3c4c2a-e275-5a8f-844a-8d88bb602faf', '5addd1d3-67f0-46a1-b83e-c6d01c9eb38d', 'A: ''I am very tired.'' B: ''___ am I.''', 'A: 「我很累。」 B: 「我也是。」', 'So', 'Too', 'Also', 'Either', 'so 為副詞，在此用於 ''So + 助動詞 + 主詞'' 句型，表示「也如此」。', 'So am I = 我也是。當你要表示跟別人一樣時，可以用 So 開頭。', '2026-07-06 10:57:16', '2026-07-06 10:57:16'),
('6aabc438-84e6-5010-aeba-019d5ec01d37', 'e510adb6-1da1-40d9-8350-4be6be0cf60d', '___ kind of music do you enjoy listening to?', '你喜歡聽什麼樣的音樂？', 'what', 'which', 'some', 'any', '限定詞 (形容詞用法)', 'what 後面常接名詞來詢問「種類」。', '2026-07-05 12:27:18', '2026-07-05 12:27:18');
